    function insT(p, blocks, warnItems) { var ti = partSeq.indexOf(p); if (ti < 0 || !THEORY[ti] || !THEORY[ti].blocks) return; var bl = THEORY[ti].blocks; if (blocks && blocks.length) { var wi = -1; for (var i = 0; i < bl.length; i++) if (bl[i].k === "note" && bl[i].v === "warn") wi = i; bl.splice.apply(bl, [(wi < 0 ? bl.length : wi), 0].concat(blocks)); } if (warnItems && warnItems.length) { var w = null; for (var j2 = 0; j2 < bl.length; j2++) if (bl[j2].k === "note" && bl[j2].v === "warn") w = bl[j2]; if (w && w.list) Array.prototype.push.apply(w.list, warnItems); } }
    var ADDS = [{"p":"PART 2. 압류대상·압류금지재산·압류 제한","q":[{"answer":"X","text":"체납자와 그 동거가족에게 필요한 6개월간의 식료와 연료는 압류할 수 없다.","exp":"'6개월간'이 틀렸다. 절대적 압류금지 대상은 체납자와 그 동거가족에게 필요한 '3개월간'의 식료와 연료다. 생존에 직결되므로 다른 재산 제공 여부와 관계없이 압류할 수 없다.","src":"2025 서울시 7급"},{"answer":"X","text":"직업 또는 사업에 필요한 건물은 체납자가 체납액에 충당할 만한 다른 재산을 제공할 때에는 압류할 수 없다.","exp":"건물은 조건부 압류금지 대상이 아니어서 틀렸다. 조건부 압류금지는 직업·사업에 필요한 '기계·기구·비품' 등 동산에 적용되며, 건물은 부동산이어서 압류해도 계속 사용할 수 있으므로 제한 없이 압류할 수 있다.","src":"2025 서울시 7급"}],"tb":[],"wi":[]},{"p":"PART 3. 압류의 효력과 재산유형별 압류","q":[{"answer":"X","text":"세무공무원은 체납자와 그 배우자의 공유재산으로서 배우자와 공동으로 점유하고 있는 동산 또는 유가증권은 압류할 수 없다.","exp":"압류할 수 없다는 부분이 틀렸다. 체납자가 배우자와 공동으로 점유하는 동산 또는 유가증권은 부부공유재산이라도 압류할 수 있다. 체납자가 단독 점유하거나 배우자와 공동 점유하는 동산·유가증권 모두 압류 대상이다.","src":"2025 서울시 7급"},{"answer":"O","text":"체납자가 그 배우자와 공동으로 점유하고 있는 동산 또는 유가증권은 부부의 공유재산이더라도 압류할 수 있다.","exp":"부부공유 동산·유가증권은 체납자가 단독 점유하든 배우자와 공동 점유하든 압류할 수 있다. 다만 공매되면 배우자에게 우선매수권이 인정되어 공유자를 보호한다는 점과 구별해 기억한다."},{"answer":"O","text":"지방자치단체의 장은 운반하기 곤란한 압류 동산을 체납자 또는 그 동산을 사용하거나 수익할 권리를 가진 제3자에게 보관하게 한 경우에는 지방세 징수에 지장이 없다고 인정되면 그 동산의 사용 또는 수익을 허가할 수 있다.","exp":"운반이 곤란한 압류 동산을 체납자나 사용·수익권자인 제3자에게 보관하게 한 경우, 징수에 지장이 없다고 인정되면 사용·수익을 허가할 수 있다. 보관자는 선량한 관리자의 주의로 보관할 의무를 진다.","src":"2025 서울시 7급"},{"answer":"X","text":"지방자치단체의 장은 운반하기 곤란한 압류 동산을 체납자에게 보관하게 한 경우에는 지방세 징수에 지장이 없더라도 그 동산의 사용 또는 수익을 허가할 수 없다.","exp":"허가할 수 없다는 부분이 틀렸다. 운반이 곤란한 압류 동산을 체납자 또는 사용·수익권 있는 제3자에게 보관하게 한 경우, 징수에 지장이 없다고 인정되면 그 동산의 사용 또는 수익을 허가할 수 있다."}],"tb":[],"wi":[]},{"p":"PART 6. 공매의 요건과 절차","q":[{"answer":"X","text":"공매보증금은 반드시 국채나 지방채로만 납부해야 한다.","exp":"반드시 국채나 지방채로만 납부해야 한다는 부분이 틀렸다. 공매보증금은 금전으로 납부하는 것이 원칙이며 국공채, 증권시장에 상장된 증권 또는 보증보험증권으로 갈음할 수 있어 납부 수단이 국채·지방채로 한정되지 않는다.","src":"2025 서울시 7급"},{"answer":"X","text":"공매는 공매재산이 있는 지방자치단체 청사에서만 진행해야 한다.","exp":"청사에서만 진행해야 한다는 부분이 틀렸다. 공매 장소는 관할 지방자치단체 청사 또는 공매재산 소재지 지방자치단체 청사가 원칙이나, 필요하다고 인정되면 다른 장소에서도 공매할 수 있다.","src":"2025 서울시 7급"},{"answer":"O","text":"공매는 관할 지방자치단체의 청사나 공매재산 소재지의 지방자치단체 청사에서 하는 것이 원칙이나, 필요하다고 인정되는 경우에는 다른 장소에서도 할 수 있다.","exp":"공매장소는 청사가 원칙이되 필요 시 다른 장소도 가능하다. '청사에서만'이라는 절대적 표현으로 예외를 배제하면 틀린 지문이 된다."},{"answer":"X","text":"매각예정가격은 지방자치단체의 장의 재량으로 결정하므로 감정인에게 평가를 의뢰할 수 없다.","exp":"감정인에게 평가를 의뢰할 수 없다는 부분이 틀렸다. 매각예정가격은 지방자치단체의 장이 직접 결정하는 것이 원칙이나, 직접 결정하기 곤란하면 감정인에게 평가를 의뢰하여 그 가액을 참작할 수 있다.","src":"2025 서울시 7급"},{"answer":"O","text":"매각예정가격은 지방자치단체의 장이 결정하되, 직접 결정하기 어려운 경우에는 감정인에게 평가를 의뢰하여 그 가액을 참작할 수 있다.","exp":"매각예정가격 결정은 지자체장이 원칙이나 감정인 평가 의뢰라는 보완 수단이 열려 있다. '감정 의뢰가 불가능하다'고 하면 틀린 설명이며, 부동산은 감정평가법인등, 기타 재산은 해당 분야 5년 이상 종사 전문가가 감정한다."}],"tb":[],"wi":[]},{"p":"PART 8. 청산·체납처분 유예·정리보류","q":[{"answer":"O","text":"체납처분의 목적물인 총재산의 추산가액이 체납처분비에 충당하고 남을 여지가 없을 때에는 체납처분을 중지하여야 한다.","exp":"총재산의 추산가액이 체납처분비조차 충당하지 못하면 무익한 절차이므로 체납처분 중지는 의무('중지하여야 한다')다. 담보채권 우선으로 남을 여지가 없는 경우와 함께 두 가지 중지 사유를 이룬다.","src":"2025 서울시 7급"},{"answer":"X","text":"체납처분의 목적물인 총재산의 추산가액이 체납처분비에 충당하고 남을 여지가 없을 때에는 체납처분을 중지할 수 있다.","exp":"총재산 추산가액이 체납처분비에 충당하고 남을 여지가 없을 때의 체납처분 중지는 재량('중지할 수 있다')이 아니라 의무('중지하여야 한다')다. 무익한 절차를 강제로 종료시키는 규정이다."},{"answer":"X","text":"지방자치단체의 장은 체납자가 재산의 압류나 압류재산의 매각을 유예함으로써 사업을 정상적으로 운영할 수 있게 되어 체납액을 징수할 수 있다고 인정될 경우에는 그 체납액에 대하여 체납처분에 의한 재산의 압류나 압류재산의 매각을 대통령령으로 정하는 바에 따라 중지하여야 한다.","exp":"'중지하여야 한다'가 틀렸다. 사업 정상 운영으로 체납액 징수가 가능하다고 인정되면 압류나 매각을 유예할 수 있는 것이며(재량), 반드시 중지하여야 하는 의무가 아니다. 유예 기간은 유예한 날의 다음 날부터 1년 이내다.","src":"2025 서울시 7급"},{"answer":"O","text":"지방자치단체의 장은 체납처분이 종결되고 체납액에 충당된 배분금액이 그 체납액보다 적을 때 정리보류를 할 수 있다.","exp":"배분금액이 체납액보다 적어 남은 체납액을 징수할 재력이 없다고 판단되면 정리보류할 수 있다(재량). '많을 때'로 바꾸면 완납된 것이어서 정리보류할 이유가 없어 틀린 지문이 된다.","src":"2025 서울시 7급"},{"answer":"X","text":"지방자치단체의 장은 체납처분이 종결되고 체납액에 충당된 배분금액이 그 체납액보다 많을 때 정리보류를 할 수 있다.","exp":"'많을 때'가 틀렸다. 정리보류는 배분금액이 체납액보다 '적을 때', 즉 남은 체납액을 걷을 재력이 없다고 판단될 때 하는 것이다. 배분금액이 체납액보다 많으면 이미 완납된 것이라 정리보류 대상이 아니다."}],"tb":[],"wi":[]}];
    for (var ai = 0; ai < ADDS.length; ai++) { insQ(ADDS[ai].p, ADDS[ai].q); insT(ADDS[ai].p, ADDS[ai].tb, ADDS[ai].wi); }
