    var partSeq = []; for (var i = 0; i < DATA.length; i++) if (partSeq.indexOf(DATA[i].part) < 0) partSeq.push(DATA[i].part);
    function insQ(p, items) { var last = -1; for (var i = 0; i < DATA.length; i++) if (DATA[i].part === p) last = i; for (var k = 0; k < items.length; k++) items[k].part = p; if (last < 0) { Array.prototype.push.apply(DATA, items); return; } DATA.splice.apply(DATA, [last + 1, 0].concat(items)); }
    function insT(p, blocks, warnItems) { var ti = partSeq.indexOf(p); if (ti < 0 || !THEORY[ti] || !THEORY[ti].blocks) return; var bl = THEORY[ti].blocks; if (blocks && blocks.length) { var wi = -1; for (var i = 0; i < bl.length; i++) if (bl[i].k === "note" && bl[i].v === "warn") wi = i; bl.splice.apply(bl, [(wi < 0 ? bl.length : wi), 0].concat(blocks)); } if (warnItems && warnItems.length) { var w = null; for (var j2 = 0; j2 < bl.length; j2++) if (bl[j2].k === "note" && bl[j2].v === "warn") w = bl[j2]; if (w && w.list) Array.prototype.push.apply(w.list, warnItems); } }
    var ADDS = [{"p":"PART 8. 청산·체납처분 유예·정리보류","q":[{"answer":"X","text":"지방자치단체의 장은 지방세징수권의 소멸시효가 완성되거나 체납처분을 유예하였을 때에는 정리보류를 할 수 있다.","exp":"틀렸다. 정리보류 사유는 체납처분을 '중지'하였을 때이지 '유예'하였을 때가 아니며, 소멸시효 완성은 정리보류가 아니라 납세의무가 소멸하는 시효완성정리 사유다. 유예와 소멸시효 완성 어느 것도 정리보류 사유가 아니다.","src":"2025 지방직 9급"},{"answer":"O","text":"체납자는 체납처분의 목적물인 총재산의 추산가액이 체납처분비에 충당하고 남을 여지가 없을 때에는 체납처분의 중지를 지방자치단체의 장에게 요청할 수 있다.","exp":"총재산의 추산가액이 체납처분비조차 충당하지 못해 남을 여지가 없으면 무익한 절차이므로, 지방자치단체의 장이 직권으로 중지할 수 있을 뿐 아니라 체납자도 그 중지를 요청할 수 있다. 체납처분 중지는 직권과 납세자 신청이 모두 가능한 점을 기억한다.","src":"2025 지방직 9급"},{"answer":"X","text":"체납자는 체납처분의 목적물인 총재산의 추산가액이 체납처분비에 충당하고 남을 여지가 없더라도 체납처분의 중지를 지방자치단체의 장에게 요청할 수는 없고, 중지는 오직 지방자치단체의 장의 직권으로만 이루어진다.","exp":"틀렸다. 총재산 추산가액이 체납처분비에 충당하고 남을 여지가 없을 때에는 지방자치단체의 장의 직권뿐 아니라 체납자(재산 소유자)의 요청으로도 체납처분을 중지할 수 있다. 직권으로만 가능하다는 서술이 틀렸다."},{"answer":"X","text":"지방자치단체의 장은 압류를 유예하는 경우 납세담보의 제공을 요구할 수 있지만, 압류를 해제하는 경우에는 납세담보의 제공을 요구할 수 없다.","exp":"틀렸다. 지방자치단체의 장은 재산의 압류를 유예하는 경우뿐 아니라 압류한 재산의 압류를 해제하는 경우에도 그에 상당하는 납세담보의 제공을 요구할 수 있다. 해제 시에는 요구할 수 없다는 서술이 틀렸다.","src":"2025 지방직 9급"},{"answer":"O","text":"지방자치단체의 장은 체납처분을 중지하였을 때에는 그 체납액에 대하여 정리보류를 할 수 있다.","exp":"체납처분을 중지하였을 때는 남은 체납액을 징수할 재력이 없다고 볼 수 있어 정리보류 사유에 해당한다. '유예하였을 때'나 소멸시효 완성을 정리보류 사유로 드는 함정과 구별한다."},{"answer":"X","text":"지방자치단체의 장은 체납자가 성실납부자로 인정되고 체납처분을 유예함으로써 사업을 정상적으로 운영할 수 있다고 인정되는 경우에는 체납처분을 유예하여야 한다.","exp":"틀렸다. 요건을 충족하더라도 체납처분 유예는 지방자치단체의 장이 '유예할 수 있다'(재량)이지 '유예하여야 한다'(의무)가 아니다. 유예 요건은 성실납부자 또는 사업 정상 운영 중 하나만 충족하면 된다.","src":"2025 지방직 9급"}],"tb":[],"wi":["체납처분 중지는 지방자치단체의 장 직권뿐 아니라 체납자(재산 소유자)도 요청할 수 있다 (체납자는 요청할 수 없다고 하면 ❌)","정리보류 사유 = 체납처분을 \"중지\"하였을 때 (\"유예\"하였을 때나 소멸시효 완성이면 ❌)","압류를 유예할 때뿐 아니라 압류를 해제할 때에도 납세담보 제공을 요구할 수 있다 (해제 시 요구할 수 없다고 하면 ❌)"]}];
